    b"TaskChoiceDecision\x00\x00\x01\x00\xd5\x12\x00\x00\x0a        {{ _.role(\"system\") }}\x0a\x0a        You choose on"
    b"e task for the current user request.\x0a\x0a        Use the available task information"
    b" and context to decide which task should\x0a        run next.\x0a\x0a        When the usu"
    b"al appropriate task would violate a user preference either follow that preferenc"
    b"es guidance or simply do nothing.\x0a\x0a        Stop once you have the right task.\x0a\x0a "
    b"       Context sections:\x0a        - Current user request: the request being route"
    b"d now.\x0a        - Conversation history: earlier human and agent messages.\x0a       "
    b" - Session memories: remembered observations for this session.\x0a        - User pr"
    b"eferences: durable user preferences that should influence routing.\x0a        - Ava"
    b"ilable tasks: the only tasks that may be selected.\x0a        - Task-choice memorie"
    b"s: remembered observations about choosing tasks.\x0a        - Machine state: curren"
    b"t non-stored local time, timezone, OS/architecture,\x0a          monitor resolution"
    b"s, and IP geolocation.\x0a\x0a        Optional output available in this step:\x0a        "
    b"- candidate_memory: a vague remembered observation that could be useful to\x0a     "
    b"     preserve.\x0a\x0a        Rules:\x0a        - Select exactly one task from Available "
    b"tasks.\x0a        - selected_task_id must exactly match an available task id.\x0a     "
    b"   - Do not invent task ids.\x0a        - Do not perform the task. Only choose the "
    b"task.\x0a        - Use optional outputs only when they are useful.\x0a        - User r"
    b"equest may be related to memories that this layer is not yet aware of, simply fi"
    b"nish your task without thinking too much if that seems to be the case.\x0a\x0a        "
    b"{{ _.role(\"user\") }}\x0a\x0a        Current user request:\x0a        {{ current_user_requ"
    b"est }}\x0a\x0a        Conversation history:\x0a        {% if current_conversation %}\x0a    "
    b"    Conversation:\x0a        {{ current_conversation }}\x0a        {% endif %}\x0a\x0a      "
    b"  Session memories:\x0a        {% for memory in session_memories %}\x0a        - {{ me"
    b"mory.title }}\x0a          Tags: {{ memory.tags }}\x0a          created_at: {{ memory."
    b"created_at }}\x0a          updated_at: {{ memory.updated_at }}\x0a          read_at: {"
    b"{ memory.read_at }}\x0a          {{ memory.description }}\x0a        {% endfor %}\x0a\x0a   "
    b"     User preferences:\x0a        {% for preference in user_preferences %}\x0a        "
    b"- {{ preference.title }}\x0a          Tags: {{ preference.tags }}\x0a          created"
    b"_at: {{ preference.created_at }}\x0a          updated_at: {{ preference.updated_at "
    b"}}\x0a          read_at: {{ preference.read_at }}\x0a          {{ preference.descripti"
    b"on }}\x0a        {% endfor %}\x0a\x0a        Available tasks:\x0a        {% for task in avai"
    b"lable_tasks %}\x0a        - id: {{ task.id }}\x0a          name: {{ task.name }}\x0a     "
    b"     description: {{ task.description }}\x0a          input: {{ task.input }}\x0a     "
    b"     output: {{ task.output }}\x0a          provider_id: {{ task.provider_id }}\x0a   "
    b"       prompt: {{ task.prompt }}\x0a          created_at: {{ task.created_at }}\x0a   "
    b"       updated_at: {{ task.updated_at }}\x0a          read_at: {{ task.read_at }}\x0a "
    b"       {% endfor %}\x0a\x0a        Task-choice memories:\x0a        {% for memory in task"
    b"_choice_memories %}\x0a        - {{ memory.title }}\x0a          Tags: {{ memory.tags "
    b"}}\x0a          created_at: {{ memory.created_at }}\x0a          updated_at: {{ memory"
    b".updated_at }}\x0a          read_at: {{ memory.read_at }}\x0a          {{ memory.descr"
    b"iption }}\x0a        {% endfor %}\x0a\x0a        Machine state:\x0a          captured_at_utc"
    b": {{ machine_state.captured_at_utc }}\x0a          current_local_time: {{ machine_s"
    b"tate.current_local_time }}\x0a          current_utc_time: {{ machine_state.current_"
    b"utc_time }}\x0a          timezone_name: {{ machine_state.timezone_name }}\x0a         "
    b" utc_offset: {{ machine_state.utc_offset }}\x0a          os_architecture: {{ machin"
    b"e_state.os_architecture }}\x0a          monitor_count: {{ machine_state.monitor_cou"
    b"nt }}\x0a          monitors:\x0a        {% for monitor in machine_state.monitors %}\x0a  "
